import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Device & System Tools","description":"","frontmatter":{},"headers":[],"relativePath":"features/device-tools.md","filePath":"features/device-tools.md"}'),i={name:"features/device-tools.md"};function d(s,e,l,n,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="device-system-tools" tabindex="-1">Device &amp; System Tools <a class="header-anchor" href="#device-system-tools" aria-label="Permalink to &quot;Device &amp; System Tools&quot;">​</a></h1><p>Lyra Code includes comprehensive device diagnostics and system interaction capabilities.</p><h2 id="device-information" tabindex="-1">Device Information <a class="header-anchor" href="#device-information" aria-label="Permalink to &quot;Device Information&quot;">​</a></h2><p>The Device Information page provides a complete hardware and software overview:</p><h3 id="hardware" tabindex="-1">Hardware <a class="header-anchor" href="#hardware" aria-label="Permalink to &quot;Hardware&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Details</th></tr></thead><tbody><tr><td>Manufacturer &amp; Model</td><td>Device brand and model identifier</td></tr><tr><td>Android Version</td><td>OS version and API level</td></tr><tr><td>CPU / Hardware</td><td>Processor model and hardware platform</td></tr><tr><td>ABI</td><td>Supported binary interfaces (arm64-v8a, etc.)</td></tr><tr><td>Memory</td><td>Total and available RAM</td></tr><tr><td>Storage</td><td>Internal storage capacity and usage</td></tr><tr><td>Display</td><td>Resolution, density, and refresh rate</td></tr><tr><td>Network</td><td>Connection type, carrier info</td></tr><tr><td>Bluetooth</td><td>Adapter status and capabilities</td></tr><tr><td>Battery</td><td>Level, health, charging status, temperature</td></tr></tbody></table><h2 id="hardware-inspection-agent" tabindex="-1">Hardware Inspection Agent <a class="header-anchor" href="#hardware-inspection-agent" aria-label="Permalink to &quot;Hardware Inspection Agent&quot;">​</a></h2><p>The Agent can perform hardware checks for:</p><ul><li><strong>Device diagnostics</strong> — Identify hardware issues and anomalies</li><li><strong>Troubleshooting</strong> — Get AI-assisted guidance for device problems</li><li><strong>Hardware comparison</strong> — Compare specs when evaluating devices</li></ul><h2 id="installed-app-recognition" tabindex="-1">Installed App Recognition <a class="header-anchor" href="#installed-app-recognition" aria-label="Permalink to &quot;Installed App Recognition&quot;">​</a></h2><p>Scan and analyze installed applications:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>App listing</td><td>Browse all, user, or system apps</td></tr><tr><td>Package names</td><td>Identify packages and versions</td></tr><tr><td>APK sizes</td><td>View installation footprint</td></tr><tr><td>Signing certificates</td><td>SHA-256 certificate verification</td></tr><tr><td>Search</td><td>Find apps by name or package</td></tr><tr><td>Pagination</td><td>Handle large app lists efficiently</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Security</p><p>App recognition helps identify suspicious or unauthorized applications through signing certificate verification.</p></div><h2 id="shizuku-root-tools" tabindex="-1">Shizuku &amp; Root Tools <a class="header-anchor" href="#shizuku-root-tools" aria-label="Permalink to &quot;Shizuku &amp; Root Tools&quot;">​</a></h2><p>For advanced users, Lyra Code offers system-level tools:</p><h3 id="shizuku-shell" tabindex="-1">Shizuku Shell <a class="header-anchor" href="#shizuku-shell" aria-label="Permalink to &quot;Shizuku Shell&quot;">​</a></h3><ul><li>Execute commands as Android shell user</li><li><code>pm</code> commands for package management</li><li><code>cmd</code> and <code>dumpsys</code> for system diagnostics</li><li>Read <code>/data</code> paths with shell permissions</li></ul><h3 id="root-commands" tabindex="-1">Root Commands <a class="header-anchor" href="#root-commands" aria-label="Permalink to &quot;Root Commands&quot;">​</a></h3><ul><li>Configurable <code>su</code> command</li><li>Permission fallback chain</li><li>Full command preview before execution</li></ul><div class="danger custom-block"><p class="custom-block-title">Important</p><p>System-level tools can be <strong>disabled independently</strong> from the Agent settings page. Both Shizuku and root tools require <strong>explicit per-action user approval</strong>.</p></div><h2 id="theme-display" tabindex="-1">Theme &amp; Display <a class="header-anchor" href="#theme-display" aria-label="Permalink to &quot;Theme &amp; Display&quot;">​</a></h2><p>Lyra Code offers extensive visual customization:</p><h3 id="theme-modes" tabindex="-1">Theme Modes <a class="header-anchor" href="#theme-modes" aria-label="Permalink to &quot;Theme Modes&quot;">​</a></h3><ul><li><strong>Light</strong> — Clean, bright interface</li><li><strong>Dark</strong> — Eye-friendly dark mode</li><li><strong>System</strong> — Follow device theme settings</li></ul><h3 id="material-you" tabindex="-1">Material You <a class="header-anchor" href="#material-you" aria-label="Permalink to &quot;Material You&quot;">​</a></h3><p>Optional dynamic color support that derives colors from your wallpaper without changing the app layout.</p><h3 id="font-refresh-rate" tabindex="-1">Font &amp; Refresh Rate <a class="header-anchor" href="#font-refresh-rate" aria-label="Permalink to &quot;Font &amp; Refresh Rate&quot;">​</a></h3><ul><li>Adjustable font size with live preview</li><li>System-following mode for font scaling</li><li>Refresh rate preference: 30 Hz, 60 Hz, 90 Hz, or 120 Hz</li><li>Smart mode that follows system display policy</li></ul>',28)])])}const u=t(i,[["render",d]]);export{m as __pageData,u as default};
